extra.modelCss:
/* Exemplo de arquitetura (conceitual) */

/* base.css */
:root {
  --radius: 14px;
  --border: rgba(17, 24, 39, 0.12);
  --accent: #2563eb;
}

/* layout.css */
.container {
  max-width: 1100px;
  margin: 0 auto;
  padding: 16px;
}

.stack {
  display: grid;
  gap: 16px;
}

/* components.css (BEM) */
.btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  padding: 10px 14px;
  border-radius: 12px;
}

.btn--primary {
  background: var(--accent);
  color: #ffffff;
}

.card {
  border: 1px solid var(--border);
  border-radius: var(--radius);
}

.card__header {
  padding: 16px;
}

.card__body {
  padding: 0 16px 16px;
}

.card--clickable {
  cursor: pointer;
}

/* utilitários pequenos */
.muted {
  opacity: 0.75;
}

.sr-only {
  position: absolute;
  width: 1px;
  height: 1px;
  padding: 0;
  margin: -1px;
  overflow: hidden;
  clip: rect(0, 0, 0, 0);
  white-space: nowrap;
  border: 0;
}
